    loader = SecureModelLoader(
        cache_dir="./secure_model_cache",
        strict_security=True,
    )

    # For demonstration, create a model directly using torchvision
    # (In production, you would download from a URL with hash verification)
    logger.info("\nStep 1: Loading pretrained model with security checks...")

    # Create a pretrained model (simulating download)
    model = torchvision_models.resnet18(weights=None)

    # Demonstrate the security scanning on the model's state dict
    detector = ModelBackdoorDetector()
    state_dict = model.state_dict()

    anomalies = detector.check_weight_anomalies(state_dict)
    if anomalies:
        logger.warning(f"Found {len(anomalies)} anomalies in model weights")
        for a in anomalies:
            logger.warning(f"  {a}")
    else:
        logger.info("No weight anomalies detected.")

    # Step 2: Prepare custom dataset
    logger.info("\nStep 2: Preparing custom dataset...")
    num_classes = 10
    train_loader, val_loader = create_sample_dataset(
        num_samples=200, num_classes=num_classes
    )

    # Step 3: Fine-tune with security monitoring
    logger.info("\nStep 3: Fine-tuning with security monitoring...")
    fine_tuner = SecureFineTuner(
        model=model,
        num_classes=num_classes,
        freeze_backbone=True,
        learning_rate=0.001,
    )

    num_epochs = 3
    for epoch in range(1, num_epochs + 1):
        train_loss, train_acc = fine_tuner.train_epoch(train_loader, epoch)
        val_loss, val_acc = fine_tuner.evaluate(val_loader)
        logger.info(f"  Validation - Loss: {val_loss:.4f}, Accuracy: {val_acc:.2f}%")

    # Final integrity check
    logger.info("\nStep 4: Final integrity verification...")
    integrity_ok = fine_tuner.verify_frozen_weights_integrity()
    if integrity_ok:
        logger.info("All frozen weights integrity checks passed.")
    else:
        logger.error("INTEGRITY CHECK FAILED - frozen weights were modified!")

    # Step 5: Save fine-tuned model
    logger.info("\nStep 5: Saving fine-tuned model...")
    output_path = "./secure_model_cache/finetuned_model.pth"
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    fine_tuner.save_model(output_path)

    logger.info("\n" + "=" * 60)
    logger.info("Pipeline completed successfully!")
    logger.info("=" * 60)

    return fine_tuner.model


